// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

// Get the transcript array from the input
const transcript = $input.item.json.transcript;

// Initialize arrays to separate messages
let conversation = [];

// Process each transcript entry
transcript.forEach((entry, index) => {
  const role = entry.role === 'agent' ? 'Agent' : 'User';
  const message = entry.message;

  conversation.push(`${role}: ${message}`);
});

// Combine into a single formatted message
const combinedMessage = conversation.join('\n\n');

// Return the combined transcript
return {
  json: {
    combined_transcript: combinedMessage,
    total_messages: transcript.length,
    conversation_id: $input.item.json.conversation_id,
    agent_id: $input.item.json.agent_id,
    status: $input.item.json.status
  }
};

